var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"누구시죠?","JPN":"どなたですか？","ENG":"Who am I speaking to?","TWN":"你是誰？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"다이애나 프리하트 부인?","JPN":"ダイアナ・プラハト夫人？","ENG":"Mrs. Diana Freeheart?","TWN":"黛安娜·普立哈特夫人？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"실례합니다. 저희는 관리국 수사청에서 나왔습니다.","JPN":"いきなり失礼いたします。我々は管理局の捜査庁から参りました。","ENG":"Excuse me. We're investigators from the Administration.","TWN":"抱歉打擾了。我們來自管理局監察廳。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"에드윈 프리하트. 이 사람이 부인의 남편 분이 맞습니까?","JPN":"エッドウィン・プラハト。この方が夫人のご主人で間違いはないでしょうか？","ENG":"Edwin Freeheart. Is this person your husband?","TWN":"艾德溫·普立哈特，請問這個人是你的丈夫嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네… 맞는데요.","JPN":"はい……そうですけど。","ENG":"Yes... He is.","TWN":"是的……沒錯。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"지금 연구소에서 근무중일 텐데, 뭣 때문에 찾으시죠?","JPN":"今は研究所で働いていますが、主人に何か？","ENG":"He's probably working at the lab right now. What brings you here?","TWN":"他現在應該在研究所。你們為什麼來找我？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"유감스럽지만, 남편 분께선 지금 행방불명입니다.","JPN":"申し上げにくいのですが、ご主人は、現在行方不明になっています。","ENG":"We're sorry to tell you this news, but your husband is currently missing.","TWN":"抱歉，你的丈夫目前失蹤了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"사기를 치고 싶은 거라면 다른 곳을 알아보시죠. 전 지금 철야근무로 사흘 밤을 새서 무척 피곤한 상태니까요.","JPN":"詐欺に付き合っている暇はないんです。私はこの三日間徹夜で働いて、すごく疲れているので。","ENG":"If you're looking to pull a scam, you've got the wrong person. I've been working for three nights straight and I'm extremely tired.","TWN":"如果你想詐騙，請另找他人。我已經連續三個晚上熬夜工作了，現在沒有精力聽你說這些。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"에드윈 프리하트는 현재 관리국 기술보안정책을 위반한 중범죄자로 전세계에 수배된 상황입니다. 지금 TV를 켜면 확인하실 수 있을 거예요.","JPN":"エッドウィン・プラハト氏は、現在管理局のテクノロジー保安法に違反した重犯罪者として全世界で指名手配となっています。テレビでご確認した方が早いと思いますけどね。","ENG":"Edwin Freeheart is currently wanted worldwide for violating the Administration's technology security policies. You can see it on TV right now.","TWN":"艾德溫·普立哈特目前因違反管理局的技術安全政策而作為重犯在全球範圍內被通緝。夫人你現在打開電視，就可以看到相關報導。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네? 그게… 무슨 소리죠? 잘 이해가 안 되는데.","JPN":"はい？　それは……どういうことなんですか？　ちょっと理解が追いつかないんですが。","ENG":"What? What are you talking about...? I don't quite understand.","TWN":"什麼？那個……你在說什麼？我不太明白。"},"stage":{"bg":"BACKSTREET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"자세한 설명은 내부기밀사항이라 말씀드리기 어렵군요.","JPN":"詳しい内容は機密事項ですので、お伝えするのは難しいのです。","ENG":"I'm afraid we can't share the details with you as they are classified.","TWN":"由於這是內部機密，很難為你詳細解釋。"},"stage":{"bg":"BACKSTREET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"만약 남편 분께서 돌아온다면 저희에게 알려주십시오. 더 위험한 일에 휘말리지 않도록 돕겠습니다.","JPN":"もしご主人がお戻りになられたら、私たちにお知らせください。これ以上深刻な事態に巻き込まれないよう、お手伝いいたしますので。","ENG":"If your husband returns, please let us know. We'll help you avoid getting involved in any potential danger.","TWN":"如果你丈夫回來了，請告訴我們。我們將幫助你，以防被捲入更加危險的事情。"},"stage":{"bg":"BACKSTREET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"잠깐만요.","JPN":"ちょっと待ってください。","ENG":"Wait.","TWN":"等等。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"그 사람은 인명을 구하는 침식학 연구를 하고 있어요. 대체 그게 뭐가 잘못됐다는 거죠?","JPN":"あの人は人の命を助けるために侵食学を研究しているんです。いったいそれのなにが罪に問われるようなことなんでしょうか？","ENG":"He does research on the Corruption in order to save lives. What exactly did he do wrong?","TWN":"我丈夫正在進行的是拯救生命的侵蝕學研究。到底是發生了什麼問題？"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"어젯밤, 북방합의체가 이면세계에서 비밀리에 진행하고 있던 비인도적 실험이 적발됐어요.","JPN":"昨夜、北方合意体が裏世界で内密に進めていた非人道的実験について摘発がありました。","ENG":"Last night, covert human experiments conducted by the Northern Union in the Counterside were discovered.","TWN":"昨晚，北方和議會在異界秘密進行的非人道實驗被人舉報揭發。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"침식체를 인위적으로 조작하는 대규모 프로젝트였죠. 거기엔 인체실험도 포함됩니다.","JPN":"人体実験が含まれた侵食体を人為的に改造する大規模プロジェクトです。","ENG":"It was a large-scale project aiming to artificially manipulate C.O.s. Which also involved human experimentation.","TWN":"這是一項旨在人為操縱侵蝕體的大型項目。其中還包括了人體實驗的部分。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네? 그럴 리가요. 저희 남편은 북방합의체하고 아무런 접점이 없어요.","JPN":"え？　それはありえません。主人は北方合意体とはなんの関わりもないはずです。","ENG":"What? That can't be. My husband has no ties to the Northern Union.","TWN":"什麼？怎麼可能？我的丈夫與北方和議會沒有任何聯繫。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"북방합의체는 에드윈 프리하트를 해당 프로젝트의 최고고문이자 책임자라고 발표했습니다.","JPN":"北方合意体はエッドウィン・プラハトが該当プロジェクトの最高顧問であり、責任者であるとの発表を出しています。","ENG":"The Northern Union announced that Edwin Freeheart was their chief consultant and supervisor of that project.","TWN":"北方和議會曾宣佈艾德溫·普立哈特擔任該專案的首席顧問兼負責人。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"제 남편은 가족을 아끼는 사람이에요.","JPN":"主人は家族をすごく大事にする人なんです。","ENG":"My husband is someone who cherishes his family.","TWN":"我的丈夫是一個很關心家庭的人。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"그런 사람이 가족을 속이면서 범죄를 저질렀다고요?","JPN":"そんな人が家族を騙して犯罪を犯したなんて信じられません！","ENG":"Are you saying that such a person committed crimes while deceiving his family?","TWN":"這樣的人，怎麼會瞞著家人去犯罪？"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"북방합의체는 수단방법을 가리지 않는 편이죠. 저희는 그가 일방적으로 이용당했을 가능성도 배제하지 않습니다.","JPN":"北方合意体は目的のためなら手段は選びません。我々も彼が一方的に利用されている可能性を排除してはいません。","ENG":"The Northern Union is known for not hesitating to use any means necessary. We haven't ruled out the possibility that he may have been taken advantage of by them.","TWN":"北方和議會不擇手段。我們不排除他被單方面利用的可能性。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"그래서 도와드리려는 겁니다. 만일 남편 분과 연락이 닿게 된다면 저희가 말씀드리는 지침을 따라 주십시오.","JPN":"だからこそ、手を差し伸べようとしているのです。もしご主人と連絡が取れた場合は、我々の方針に従っていただけますか。","ENG":"That's why we're here to help. If you ever get in touch with your husband, please follow the instructions we give you.","TWN":"這就是為什麼我們想幫助你。如果你能夠聯繫到你的丈夫，請按照我們給你的指示進行操作。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"잠시… 잠시만요.","JPN":"あ……ちょっと待ってください。","ENG":"Wait... hold on.","TWN":"等……等一下。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"딸 애가 있는 병원에서 연락이 왔어요.","JPN":"娘の病院から電話が。","ENG":"I'm getting a call from the hospital where my daughter is.","TWN":"是女兒醫院的號碼。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"전화 받았어요.","JPN":"はい、もしもし。","ENG":"Hello?","TWN":"我接個電話。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다음 속보입니다.</color>","JPN":"<color=#ffd34c>次のニュースです。</color>","ENG":"<color=#ffd34c>Breaking news.</color>","TWN":"<color=#ffd34c>以下為本期快訊。</color>"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"Excuse me…?","TWN":"什麼……？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"환자가 없어지다뇨? 그게 무슨 소리예요?","JPN":"娘がいなくなったって、いったいどういうことなんですか？","ENG":"She disappeared? What do you mean?","TWN":"人不見了？什​​麼意思？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>어젯밤, 북방합의체 소재의 군사구역에서 관리국 조항에 위배되는 연구자료가 적발되었습니다.</color>","JPN":"<color=#ffd34c>昨夜、北方合意体所在の軍事区域から管理局条項に違反する研究資料が摘発されました。</color>","ENG":"<color=#ffd34c>Last night, research data violating the Administration's policy was discovered in a military zone located in the Northern Union.</color>","TWN":"<color=#ffd34c>昨晚，相關人員在北方和議會發現了違反管理局條例的研究資料。</color>"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"보호자가… 일주일 전에 데려갔다고요?","JPN":"保護者が……一週間前に迎えに来ていた、ですって？","ENG":"Her guardian... took her away a week ago?","TWN":"她的監護人……一週前就帶走了她？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"아니, 잠깐만요…","JPN":"ちょっと……待ってください。","ENG":"Wait a minute...","TWN":"不，等等……"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"이게… 이게 대체…","JPN":"いったいなにがどう……","ENG":"How... could this–","TWN":"這……這到底是……"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>북방합의체 외교부는 이 프로젝트가 국가산업과는 일체 연관이 없으며…</color>","JPN":"<color=#ffd34c>北方合意体の外交省は、今回のプロジェクトについて国家事業とは一切無関係であり……</color>","ENG":"<color=#ffd34c>The Foreign Affairs Ministry of the Northern Union rebutted, stating that this project has no relation to national affairs...</color>","TWN":"<color=#ffd34c>北方和議會外交部回應了此次舉報，聲稱該項目與本國無關……</color>"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>…프로젝트에 가담했던 재외국민 연구진들의 명단을 제공하고 공개수배하기로…</color>","JPN":"<color=#ffd34c>……プロジェクトに加担していたと見られる在外国民の研究者らの名簿を公開し、指名手配を行うとの……</color>","ENG":"<color=#ffd34c>...agreeing to provide a list of overseas nationals who were involved in the project and to issue warrants for their arrest.</color>","TWN":"<color=#ffd34c>……同意提供參與該項目的海外研究人員名單，公開對其進行懸賞……</color>"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"아, 깨어났다.","JPN":"あっ、起きた。","ENG":"Oh, she's awake.","TWN":"啊，你醒了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"다행이네요. 지혈이 잘 됐나봐요.","JPN":"よかった、止血が効いたみたいです。","ENG":"Phew. Looks like the bleeding stopped.","TWN":"呼——看來血成功止住了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"힉스…?","JPN":"ヒックス……？","ENG":"Hicks...?","TWN":"希克斯……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가… 얼마나 의식을 잃었지?","JPN":"私は……どのくらい気を失っていたんだ？","ENG":"How long was I out for?","TWN":"我……失去意識多久了？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"음, 두 시간 정도 지난 것 같은데요?","JPN":"えーっと、2時間くらいでしょうか？","ENG":"Hmm, about two hours?","TWN":"唔，大概過去了兩個小時？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"시간을 낭비했어. 빨리 돌아가야…","JPN":"かなり時間をロスしてしまったな。はやく戻らねば……","ENG":"We wasted too much time. We need to go back quickly...","TWN":"浪費了太多時間。我得趕快回去……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"으윽…!","JPN":"ううっ……！","ENG":"Urrggh...!","TWN":"呃……！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"앗, 조심하세요. 엄청 높은 곳에서 떨어졌거든요.","JPN":"あっ、ゆっくり動いてください。すごく高いところから落ちたんですよ？","ENG":"Oh, be careful. You fell from quite the height.","TWN":"啊，小心點。你是從很高的地方摔下來的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그래도 다행히, 슈트가 튼튼해서 살았네요.","JPN":"幸い、スーツがすごく頑丈だったおかげで助かりましたね。","ENG":"Still, good thing the suit was sturdy enough to keep you alive.","TWN":"但幸好，這套防護服很堅固，你才活了下來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"몸은 괜찮아. 금단증상 때문에 현기증이 돈 것뿐이니까.","JPN":"特に問題はない。禁断症状によるめまいがしただけだ。","ENG":"I feel fine. I was just a bit dizzy from the withdrawal.","TWN":"我的身體沒事。我只是因為戒斷症狀而感覺頭暈而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"후우…","JPN":"ふう……","ENG":"Huu...","TWN":"呼……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"방금 그 주사기… 이터니움 정제액이네요.","JPN":"その注射って……エタニウム精製水ですよね。","ENG":"That shot... it's purified Eternium liquid.","TWN":"剛才那個注射器……是永恆之金淨化液吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침식증후군. 맞죠?","JPN":"侵食症候群、ですか？","ENG":"Corruption Syndrome. Right?","TWN":"你有侵蝕症候群。對不對？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래, 5년 넘게 승강기를 타다 보면 자연스레 얻는 지병이지.","JPN":"ああ。5年以上もこの仕事をしていたら誰でもなる病だ。","ENG":"Yes, it's something you get when you ride down the elevator regularly for over five years.","TWN":"嗯，坐了五年的升降機，不知不覺就患上了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"알아보다니 의외네. 보통은 그냥 흔한 약쟁이라고 생각하는데.","JPN":"ところで、どこでその知識を得た？　普通はただのヤク中だとしか思わないんじゃないか？","ENG":"I'm surprised you know about it. Most people just think I'm a drug addict.","TWN":"我倒是很驚訝你能察覺道。一般的人都以為我是個癮君子呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"저랑 오라버니도 걸린 적 있거든요. 주사는 비싸서 많이 못 써봤지만.","JPN":"私とお兄さんもなったことがあるんです。注射は高いのであまり使ったことはないんですが。","ENG":"Both my brother and I had it before. But we couldn't afford many shots, though.","TWN":"我和哥哥也得了這種病。注射劑價格很貴，所以我很少用。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"카운터가 되면서 병을 극복한 거야?","JPN":"カウンターになることで病気を克服したのか？","ENG":"Did becoming a Counter help you beat it?","TWN":"你是成為制裁者之後，就擺脫了侵蝕病嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"드물지만 그런 사례가 있다고는 들었는데, 여기서 이렇게 보게 될 줄은 몰랐네.","JPN":"ごく稀にそんな事例もあるとは聞いていたが、まさか直接会うことになるとは驚いたな。","ENG":"I've heard of rare cases like that, but I didn't expect to see one here.","TWN":"雖然很少見，但我也聽說過這樣的例子，沒想到在這裡看到了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"맞아요. 저는 그 덕에 살았죠.","JPN":"そうなんです。それで私は助かりました。","ENG":"That's right. That's how I'm still alive.","TWN":"沒錯。幸虧如此，我才能活下來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"늘 아쉽더라고요. 저 대신 오라버니가 카운터가 됐으면 좋았을 텐데.","JPN":"でもいつも思うんです。私じゃなくてお兄さんがカウンターになればよかったのに、って。","ENG":"I always felt regretful. It would've been better if my brother became a Counter instead of me.","TWN":"但我常常遺憾。如果我哥哥能代替我，成為制裁者就好了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다른 팀원은 어떻게 됐어?","JPN":"他のみんなはどうなった？","ENG":"Where are the other guys?","TWN":"其他隊員怎麼樣了？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"몰라요.","JPN":"わかりません。","ENG":"I don't know.","TWN":"不清楚。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"스펜서가 밑으로 떨어져서 저도 무작정 뛰어내렸거든요.","JPN":"スペンサーさんが落ちた瞬間、私も反射的に飛び降りたので。","ENG":"I jumped right after you when you fell.","TWN":"史賓瑟摔下來後，我就跟著跳了起來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그러고도 안 다친 거야? 카운터는 역시 튼튼하네.","JPN":"それで怪我がないなんて、カウンターは本当に頑丈なんだな。","ENG":"And you didn't get hurt? Counters sure are tough.","TWN":"這樣你也沒受傷？制裁者果然都不一般。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"에이, 그 정돈 아녜요. 저도 정강이뼈가 부러져서 잠깐 실신한 걸요?","JPN":"そんなこともないですよ。私も脛骨が折れちゃって一瞬失神していましたからね？","ENG":"Not quite. I broke a shinbone and passed out for a while.","TWN":"欸嘿，沒有那麼厲害。我也摔斷了小腿，暫時暈倒了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"금방 회복해서, 지금은 괜찮지만요.","JPN":"すぐに回復するので、今は大丈夫ですけど。","ENG":"I heal fast so I'm okay now, though.","TWN":"不過，我恢復得很快，現在已經沒事了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나 때문에… 그렇게까지 한 거야?","JPN":"私のためにそこまで……？","ENG":"You went through all that... for me?","TWN":"為了我……值得嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"말씀드렸잖아요? 제 임무는 스펜서를 지키는 거라고요.","JPN":"言ったじゃないですか。私の任務はスペンサーさんを守ることだって。","ENG":"I told you, my mission is to protect you.","TWN":"我不是說了嗎？我的任務是保護史賓瑟。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"자, 저한테 업히세요. 다시 위로 올라갈 테니까요.","JPN":"さあ、私の背中に掴まってください。おんぶして上まで登ります。","ENG":"Now, get on my back. I'll get us back up.","TWN":"好了，我來背你。回到上面去吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래…","JPN":"ああ……","ENG":"Okay...","TWN":"啊，好……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…잠깐만.","JPN":"……ちょっと待て。","ENG":"...Hold on.","TWN":"……等一下。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"방금 저쪽에서 목소리가 들렸어.","JPN":"今あっちの方から声がした。","ENG":"I just heard a voice coming from there.","TWN":"我剛剛聽到那邊有聲音。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"목소리라고요?","JPN":"え？　声ですか？","ENG":"A voice?","TWN":"聲音？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"여긴 스티플 제이슨 탐사대다! 누구 듣고 있나?!","JPN":"こちら探索部隊のスティープル・ジェイソンだ！　誰かいないか！？","ENG":"This is…! Stipple Jason Expedition! Does anyone copy?!","TWN":"這裡是史蒂芬·傑森勘查隊！有人在聽嗎？！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"신원미상의 적으로부터 습격당했어! 누구라도 좋으니 좀 살려줘!","JPN":"正体不明の敵から襲撃を受けた！　誰でもいい、助けてくれ！","ENG":"We've been ambushed by an unidentified enemy! Please, anyone, help us!","TWN":"我們遭遇不明敵襲！有沒有人可以來救救我們！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"여긴 스티플 제이슨 탐사대다! 누구 듣고 있나?!","JPN":"こちら探索部隊のスティープル・ジェイソンだ！　誰かいないか！？","ENG":"This is…! Stipple Jason Expedition! Does anyone copy?!","TWN":"這裡是史蒂芬·傑森勘查隊！有人在聽嗎？！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"자동반복…","JPN":"自動再生……","ENG":"It's on auto-repeat...","TWN":"自動重播……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"여기서 계속 신호를 보내고 있던 거였어.","JPN":"信号の発信源はここだったのか。","ENG":"The signal's been coming from here all along.","TWN":"訊號就是一直從這裡傳來的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"여기 시체들이 모여 있네요?","JPN":"ここに死体が集まっていますね。","ENG":"There are corpses gathered here.","TWN":"這裡都是屍體？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"1.147, 1.125, 109.425.","JPN":"1.147, 1.125, 109.425。","ENG":"1.147, 1.125, 109.425.","TWN":"1147，1125，109425。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"며칠 전 탐사도중에 받았던 구조요청과 좌표신호가 같아.","JPN":"数日前、探査中に受け取った救難信号と座標が一致している。","ENG":"The coordinates match the ones I received from the distress call a few days ago.","TWN":"座標訊號和我前幾天探索時收到的救援請求是一樣的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리보다 먼저 출발한 선발대를 이런 곳에서 볼 줄은 몰랐네.","JPN":"先発隊とこんなところで遭遇するとはね。","ENG":"I didn't think we'd run into the advance party like this.","TWN":"沒想到會在這種地方找到先遣隊。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};